SELECT upgrade.upgrade, count(*) AS change FROM (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade != 0) AS upgrade JOIN (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade = 0) AS baseline ON baseline.bldg_id = upgrade.bldg_id AND baseline."in.nhgis_tract_gisjoin" = upgrade."in.nhgis_tract_gisjoin" AND baseline.state = upgrade.state WHERE baseline.applicability = true AND upgrade.applicability = true AND coalesce(baseline."out.electricity.total.energy_consumption..kwh" - upgrade."out.electricity.total.energy_consumption..kwh", -1) < 0.001 AND coalesce(baseline."out.natural_gas.total.energy_consumption..kwh" - upgrade."out.natural_gas.total.energy_consumption..kwh", -1) < 0.001 AND coalesce(baseline."out.other_fuel.total.energy_consumption..kwh" - upgrade."out.other_fuel.total.energy_consumption..kwh", -1) < 0.001 AND coalesce(baseline."out.district_cooling.total.energy_consumption..kwh" - upgrade."out.district_cooling.total.energy_consumption..kwh", -1) < 0.001 AND coalesce(baseline."out.district_heating.total.energy_consumption..kwh" - upgrade."out.district_heating.total.energy_consumption..kwh", -1) < 0.001 AND NOT (coalesce(abs(upgrade."out.electricity.total.energy_consumption..kwh" - baseline."out.electricity.total.energy_consumption..kwh"), 0) < 0.001 AND coalesce(abs(upgrade."out.natural_gas.total.energy_consumption..kwh" - baseline."out.natural_gas.total.energy_consumption..kwh"), 0) < 0.001 AND coalesce(abs(upgrade."out.other_fuel.total.energy_consumption..kwh" - baseline."out.other_fuel.total.energy_consumption..kwh"), 0) < 0.001 AND coalesce(abs(upgrade."out.district_cooling.total.energy_consumption..kwh" - baseline."out.district_cooling.total.energy_consumption..kwh"), 0) < 0.001 AND coalesce(abs(upgrade."out.district_heating.total.energy_consumption..kwh" - baseline."out.district_heating.total.energy_consumption..kwh"), 0) < 0.001) GROUP BY 1 ORDER BY 1